import{_ as t,o as a,c as o,ae as r}from"./chunks/framework.CZdDbCC-.js";const u=JSON.parse('{"title":"API Reference","description":"","frontmatter":{"title":"API Reference","layout":"doc","editLink":false},"headers":[],"relativePath":"api-reference/operations/index.md","filePath":"api-reference/operations/index.md"}'),s={name:"api-reference/operations/index.md"};function i(n,e,d,l,c,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="api-reference" tabindex="-1">API Reference <a class="header-anchor" href="#api-reference" aria-label="Permalink to &quot;API Reference&quot;">​</a></h1><h2 id="developer-access" tabindex="-1">Developer Access <a class="header-anchor" href="#developer-access" aria-label="Permalink to &quot;Developer Access&quot;">​</a></h2><p>Developer Access can be granted to test the integration or application you are developing against your company&#39;s data in a safe sandbox environment. In order to gain access you will need an API Key for the sandbox environment.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>To request an API Key please contact your company administrator or email <a href="mailto:product@advantagecg.com" target="_blank" rel="noreferrer">product@advantagecg.com</a></p></div><p>Developer sandbox access should be used when:</p><ul><li>Developing your integration</li><li>Testing and tuning your application integration</li><li>Testing data creation before posting to Production</li></ul><h3 id="sandbox-data" tabindex="-1">Sandbox Data <a class="header-anchor" href="#sandbox-data" aria-label="Permalink to &quot;Sandbox Data&quot;">​</a></h3><p>The Sandbox data is a copy of Production data and any data created in the Sandbox will be overwritten periodically to refresh the Sandbox with more current Production data.</p><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><p>The Advantage RESTful API Reference presented in this documentation lists all endpoints and descriptions. Calls to the API are validated against an API Token which is sent in the header with a key of X-API-KEY.</p><p>For more information on this view, please refer to the Authentication section of this documentation. Once you have an API Key, you can create a simple Hello World application by following the steps listed below.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>To request an API Key please contact your company administrator or email <a href="mailto:product@advantagecg.com" target="_blank" rel="noreferrer">product@advantagecg.com</a></p></div><h3 id="hello-world-app" tabindex="-1">Hello World App <a class="header-anchor" href="#hello-world-app" aria-label="Permalink to &quot;Hello World App&quot;">​</a></h3><p>Below is a simple <em>Ruby command-line application</em>. It makes a request to the Advantage RESTful API demonstrating the functionality for operating with it. The quick example below will list all the existing tickets from your CommandCenter sandbox account. If you do not have any Tickets in the system, you can still test the sample application and expect to get an empty result set as a response.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The Sandbox instance contains a copy of <em>Production</em> data. Access should be limited to those individuals that are authorized to view Production data.</p></div><p>Create a file called hello_world.rb and copy-paste the code snippet below into the file. Ensure that you change X-API-KEY header value to match your API Key or authentication will fail.</p><p>ruby require &#39;net/http&#39; require &#39;uri&#39; require &#39;json&#39;</p><p>api_url = &#39;<a href="https://api.advantagecg.com/latest/tickets" target="_blank" rel="noreferrer">https://api.advantagecg.com/latest/tickets</a>&#39; uri = URI.parse(api_url) request = Net::HTTP::Get.new(uri)</p><p>request.basic_auth(&quot;Q6UJv7YlGTOLyoGNmfo9&quot;, &quot;NA&quot;)</p><p>req_options = { use_ssl: uri.scheme == &quot;https&quot;, }</p><p>response = Net::HTTP.start(uri.hostname, uri.port, req_options) do |http|</p><p>http.request(request)</p><p>end</p><p>puts response.code puts response.body</p><h4 id="running-the-app" tabindex="-1">Running the app <a class="header-anchor" href="#running-the-app" aria-label="Permalink to &quot;Running the app&quot;">​</a></h4><p>Run the command rb hello_world.rb to execute the code directly from the command line. You should receive a response like the example below.</p><p>shell $ rb hello_world.rb Sending request... 12345|New Ticket 23463|Another ticket record</p><p>If you don&#39;t have any tickets in your Sandbox instance, you should receive a No records found message in the shell console:</p><p>shell $ rb hello_world.rb Sending request... No records found</p><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><p>Below are some of the core concepts necessary to ensure the correct functioning of your integration.</p><ul><li><a href="#requests">Requests</a></li><li><a href="#responses">Responses</a></li><li><a href="#date-format">Date Format</a></li><li><a href="#pagination">Pagination</a></li><li><a href="#http-status-codes">HTTP Status Codes</a></li><li><a href="#authentication">Authentication</a></li></ul><h3 id="requests" tabindex="-1">Requests <a class="header-anchor" href="#requests" aria-label="Permalink to &quot;Requests&quot;">​</a></h3><p>When performing a API request you will need to use JSON body format. Make sure you provide Content-Type: application/json in the HTTP request header to ensure a properly formatted request.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>All requests to the Advantage API must use a secure connection via https and support TLSv1.2</p></div><p>The Advantage API uses appropriate HTTP verbs for each action. Access to certain actions may be limited by the access rights of the API Key.</p><table tabindex="0"><thead><tr><th>Verb</th><th>Description</th></tr></thead><tbody><tr><td>GET</td><td>Used to retrieve records from the system</td></tr><tr><td>POST</td><td>Used to create records in the system</td></tr><tr><td>PUT</td><td>Used to replace records in the system</td></tr><tr><td>PATCH</td><td>Used to update part of a record in the system</td></tr><tr><td>DELETE</td><td>Used to delete records from the system</td></tr></tbody></table><h4 id="url-format" tabindex="-1">URL Format <a class="header-anchor" href="#url-format" aria-label="Permalink to &quot;URL Format&quot;">​</a></h4><p>The naming convention for the URL is based on the following.</p><ul><li>Each request must be made to the API root for the desired version followed by the plural name of the object. For example <a href="https://api.advantagecg.com/latest/tickets" target="_blank" rel="noreferrer">https://api.advantagecg.com/latest/tickets</a></li><li>When the endpoint supports it and only a single record is requested, the ID of hte item must be appended to the URL. For example <a href="https://api.advantagecg.com/latest/tickets/1234" target="_blank" rel="noreferrer">https://api.advantagecg.com/latest/tickets/1234</a></li><li>When requesting child objects of an object you can append the child object after the object id. For example <a href="https://api.advantagecg.com/latest/tickets/1234/products" target="_blank" rel="noreferrer">https://api.advantagecg.com/latest/tickets/1234/products</a></li></ul><h3 id="responses" tabindex="-1">Responses <a class="header-anchor" href="#responses" aria-label="Permalink to &quot;Responses&quot;">​</a></h3><p>Each response sent from the API contains a success parameter which is of boolean type, indicating whether the request was successful or not. Upon success being false, an optional error parameter (string) may be given. In case of success is true, the response is always contained within a payload parameter, and additional metadata may be carried inside an additional_data parameter.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>All data is sent and received in JSON format.</p></div><details class="details custom-block"><summary>Success Response</summary><p>json { &quot;success&quot;: true, //boolean, shows if operation succeeded (similar to HTTP status) &quot;payload&quot;: null, //object in other cases &quot;additional_data&quot;: { &quot;pagination&quot;: { //for endpoints that list data &quot;start&quot;: &quot;0&quot;, &quot;limit&quot;: &quot;100&quot;, &quot;more_items&quot;: false } } }</p></details><details class="details custom-block"><summary>Error Response</summary><p>json { &quot;success&quot;: false, &quot;error&quot;: &quot;Requested service is not availabile&quot;, //main error message &quot;error_info&quot;: &quot;Please check developers.advantagecg.com&quot;, &quot;payload&quot;: null, &quot;additional_data&quot;: null }</p></details><h3 id="date-format" tabindex="-1">Date Format <a class="header-anchor" href="#date-format" aria-label="Permalink to &quot;Date Format&quot;">​</a></h3><p>All dates and times used by the API will be in ISO 8601 format 2019-01-22 08:55:59 (would be the same as 2019-01-22T08:55:59).</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>All times received by the API will be in UTC timezone.</p></div><p>The times that are sent to the API should also be converted to the UTC timezone before being sent or include the ISO 8601 offset indicator as follows 2019-01-22T08:55:59-05:00.</p><h3 id="pagination" tabindex="-1">Pagination <a class="header-anchor" href="#pagination" aria-label="Permalink to &quot;Pagination&quot;">​</a></h3><p>Most of the lists/item collections are paginated. The parameters that control the pagination are start and limit, indicating the desired offset and the items per page values.</p><p>Within the response&#39;s additional_data object, a pagination object will be set upon pagination. The additional_data.pagination will contain the given start and limit, as well as the more_items flag, indicating whether there are more items that can be fetched after the current batch. When there are, next_start will also be set which can be used for the next offset pointer.</p><p>The maximum limit value is 500.</p><h3 id="http-status-codes" tabindex="-1">HTTP Status Codes <a class="header-anchor" href="#http-status-codes" aria-label="Permalink to &quot;HTTP Status Codes&quot;">​</a></h3><p>This is a list of status codes returned by the Advantage API.</p><table tabindex="0"><thead><tr><th>Status Code</th><th>Name</th><th>Description</th></tr></thead><tbody><tr><td>200</td><td>OK</td><td>Request completed</td></tr><tr><td>201</td><td>Created</td><td>New record was created</td></tr><tr><td>400</td><td>Bad Request</td><td>Request was not understood</td></tr><tr><td>401</td><td>Unauthorized</td><td>Invalid API token or access to endpoint not allowed</td></tr><tr><td>403</td><td>Forbidden</td><td>Request not allowed</td></tr><tr><td>404</td><td>Not Found</td><td>Resource unavailable</td></tr><tr><td>410</td><td>Gone</td><td>Old resource permanently removed</td></tr><tr><td>415</td><td>Unsupported Media Type</td><td>Feature is not enabled</td></tr><tr><td>429</td><td>Too Many Requests</td><td>Rate limit has been exceeded</td></tr><tr><td>500</td><td>Internal Server Error</td><td>Invalid method</td></tr><tr><td>501</td><td>Not Implemented</td><td>Non-existent functionality</td></tr><tr><td>503</td><td>Service Unavailable</td><td>Down for maintenance</td></tr></tbody></table><h3 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h3><p>The API Key must be provided as part of the request headers using the X-API-KEY header.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>All API requests must be authenticated.</p></div><p>An API key is tied to a specific company, giving access to all the company&#39;s data. You can only have one active API key at any time. If you change the API key, all existing integrations using this API key will not be able to make successful requests against our API and stop working.</p><p>Keep in mind that API Keys should be rotated at least every 90 days.</p>',61)])])}const m=t(s,[["render",i]]);export{u as __pageData,m as default};
